public class NumberOfStepsToReduceANumberToZero_Math {

    // Approach:
    // The intuitive approach, to subtract by 1 when odd or divide by 2 when even.

    public int numberOfSteps(int num) {
        int count = 0;
        while (num > 0) {
            num = num % 2 == 0 ? num / 2 : num - 1;
            count++;
        }
        return count;
