 *         this.left = left;
 *         this.right = right;
 *     }
 * }
 */
// Note: Remember to set up a TreeNode class as the same folder as your inorder traversal algorithms.

// Time Complexity  : O(n),
// where 'n' is the number of nodes in the tree, as we are traversing every single node.
// However, this does not take into account the resizing of the array backing the ArrayList,
// depending on the size of nodes in the tree.
//
// Space Complexity : O(n),
// where 'n' is the number of nodes in the tree,
// as we are recording the value of every node into the List.
// The recursive call stack only takes up the maximum space of tree height, which is smaller than 'n'.

public class BinaryTreeInorderTraversal_Recursive {

    // Approach:
    // Using recursive function to traverse the tree, visiting the nodes in the order of:
    // 1. Left node (with another recursive call).
    // 2. Visit the root node, and add the value to the list.
    // 3. Right node (with another recursive call).

    // Wrapper method to set up and initialize the recursive function.
    public static List<Integer> inorderTraversal(TreeNode root) {
        List<Integer> integerList = new ArrayList<>();
        integerList = inorderTraversal(integerList, root);
        return integerList;
    }

    // Recursive method.
    public static List<Integer> inorderTraversal(List<Integer> integerList, TreeNode root) {
        // The base case, for when the root is null.
        if (root == null) return integerList;

        // For inorder traversal, we first visit the left node,
        integerList = inorderTraversal(integerList, root.left);
        // then we visit the root, and perform a certain operation,
        // in this case, we add the value of the root to the list.
        integerList.add(root.val);
        // Lastly, we visit the right node.
        integerList = inorderTraversal(integerList, root.right);

        // Once done, we return the list.
        return integerList;
    }
}

package com.cheehwatang.leetcode;

import java.util.HashMap;
import java.util.Map;

// Time Complexity  : O(n),
// where 'n' is the length of 'nums'.
// We traverse 'nums' to get the prefix sum and find the number of subarray that sum to 'k'.
//
// Space Complexity : O(n),
// where 'n' is the length of 'nums'.
// The maximum size of the HashMap grows linearly with the length of 'nums',
// with the worst-case when all prefix sum recorded are unique.

public class SubarraySumEqualsK {

    // Approach:
    // When it comes to Sum of Subarray, the use of Prefix Sum is especially important.
    // Prefix Sum is the sum of the current integer with the previous integer in the array (Prefix).
    // Example: nums = [1,2,3,4,5] has the prefix sum array of prefixSum = [1,3,6,10,15],
    //          where the nums[0] + 1 = 1, nums[1] + nums[0] = 2 + 1 = 3, nums[2] + nums[1] = 3 + 3 = 6, and so on.
    // Using the example above, we can determine the subarray sum of any subarray using prefix sum.
    // To get the subarray sum of nums[2] to nums[4] == 3 + 4 + 5 == 12,
    // we can get from prefixSum[5] - prefixSum[1] == 15 - 3 == 12.
    //
    // With Prefix Sum, we can evaluate if subarray sum is equal to k by prefixSum[j] - prefixSum[i] == k.
    // Shifting the equation around we get prefixSum[j] - k == prefixSum[i], where j > i.
    // Thus, we can store the prefix sum of i-th element in 'nums' in a Hashtable, and check for each j-th element
    // if prefixSum[j] - k is in the Hashtable.

    public int subarraySum(int[] nums, int k) {

        // Store the frequency as there could be multiple subarrays with the same prefix sum.
        Map<Integer, Integer> map = new HashMap<>();
        // The first element for (i - 1) is always 0.
        map.put(0, 1);

        int prefixSum = 0;
        int count = 0;
        for (int num : nums) {
            prefixSum += num;
            // Add to the count if prefixSum - k is found.
            count += map.getOrDefault(prefixSum - k, 0);
            map.put(prefixSum, map.getOrDefault(prefixSum, 0) + 1);
        }
        return count;
    }
}

